import React, { useEffect, useRef, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useId } from '@andes/context';
import { VisuallyHidden } from '@andes/visually-hidden';
import { useThemeContext } from '@andes/themes';
import FeedbackPositive16 from '@andes/icons/FeedbackPositive16';
import IndeterminateIcon from './IndeterminateIcon';
import { namespace } from '../constants';
import { WARNING_LABEL } from '../constants/warnings';
import { LABEL_POSITION_LEFT } from '../constants/labelPositions';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import warning from '@andes/common/build/utils/warning';

/**
 * Checkbox is an interactive component that allows the user make multiple selections in an options list.
 */

/**
 * @typedef {Object} CheckboxInternalProps
 * @prop {boolean} [srHidden]
 */

/** @typedef {import('../../index').CheckboxProps} CheckboxPublicProps */

/** @typedef {CheckboxInternalProps & CheckboxPublicProps} CheckboxProps */

/** @type {React.FunctionComponent<CheckboxProps>} */
const Checkbox = (props) => {
  const {
    checked,
    className,
    defaultChecked,
    disabled = false,
    error = false,
    highlight = false,
    id,
    indeterminate = false,
    inputProps = {},
    label,
    labelPosition = 'right',
    onChange,
    srHidden = false,
    srLabel,
    ref,
  } = props;

  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const { current: isControlled } = useRef(typeof checked !== 'undefined');
  const [isChecked, setIsChecked] = useState(defaultChecked || checked);

  warning(Boolean(label || srLabel || srHidden), WARNING_LABEL);

  useEffect(() => {
    if (isControlled && checked !== undefined) {
      setIsChecked(checked);
    }
  }, [checked, isControlled]);

  const componentId = useId(id);
  const srLabelId = `${componentId}-srLabel`;
  /** @type {React.RefObject<HTMLInputElement | null>} */
  const inputRef = useRef(null);

  /** @type {React.ChangeEventHandler<HTMLInputElement>} */
  const handleChange = (event) => {
    if (!isControlled) setIsChecked(event.target.checked);

    if (typeof onChange === 'function') onChange(event);
  };

  const checkboxClassnames = classNames(namespace, className, {
    [`${namespace}--error`]: error,
    [`${namespace}--highlight`]: highlight,
    [`${namespace}--label-left`]: labelPosition === LABEL_POSITION_LEFT,
    [`${namespace}--indeterminate`]: indeterminate && isChecked,
    [`${namespace}--disabled`]: disabled,
  }, getThemedComponentClasses?.('checkbox'));

  const labelClassnames = classNames(`${namespace}__label`, {
    [`${namespace}__label-text`]: label,
  });

  const Wrapper = label ? 'label' : 'div';

  useEffect(() => {
    if (inputRef?.current) {
      inputRef.current.indeterminate = (indeterminate && isChecked) || false;
    }
  }, [inputRef, indeterminate, isChecked]);

  return (
    // disable a11y rule due to a false positive
    // eslint-disable-next-line jsx-a11y/label-has-associated-control
    <Wrapper
      className={checkboxClassnames}
      ref={ref}
      data-andes-checkbox
      data-andes-checkbox-variant={highlight ? 'highlight' : undefined}
      {...computeDataAndesState({
        checked: isChecked,
        disabled,
        indeterminate: indeterminate && isChecked,
        error: error && !isChecked,
      })}
      {...themeHash}
    >
      <span className={`${namespace}__checkbox`} data-andes-checkbox-container>
        <input
          {...inputProps}
          ref={inputRef}
          checked={checked}
          className={`${namespace}__input`}
          defaultChecked={defaultChecked}
          disabled={disabled}
          id={componentId}
          onChange={handleChange}
          type="checkbox"
          {...srLabel ? { 'aria-labelledby': srLabelId } : {}}
          data-andes-checkbox-input
        />
        <span className={`${namespace}__icon`}>
          {(indeterminate && isChecked)
            ? <IndeterminateIcon />
            : <FeedbackPositive16 color="currentColor" />}
        </span>
      </span>
      {label && (
        <span
          aria-hidden={!!srLabel || undefined}
          className={labelClassnames}
          data-andes-checkbox-label
        >
          {label}
        </span>
      )}
      {srLabel && <VisuallyHidden id={srLabelId}>{srLabel}</VisuallyHidden>}
    </Wrapper>
  );
};

Checkbox.displayName = 'Checkbox';

Checkbox.propTypes = {
  checked: PropTypes.bool,
  className: PropTypes.string,
  defaultChecked: PropTypes.bool,
  disabled: PropTypes.bool,
  error: PropTypes.bool,
  highlight: PropTypes.bool,
  id: PropTypes.string,
  indeterminate: PropTypes.bool,
  inputProps: PropTypes.shape({}),
  label: PropTypes.oneOfType([PropTypes.string, PropTypes.node]),
  labelPosition: PropTypes.oneOf(['left', 'right']),
  onChange: PropTypes.func,
  srLabel: PropTypes.string,
  srHidden: PropTypes.bool,
};

export default Checkbox;
